previewCss:
.darma-loader-darma-custom-140 {
  color: #0f766e;
width: 49px;
aspect-ratio: 1;
--c: conic-gradient(from -90deg,currentColor 90deg,#0000 0);
background: var(--c), var(--c);
background-size: 40% 40%;
animation: darma-loader-darma-custom-140-l20 1.5s infinite;
}
@keyframes darma-loader-darma-custom-140-l20 {
0%,
20% {background-position: 0 0 ,0 calc(100%/3)}
33% {background-position: 0 0 ,calc(100%/3) calc(100%/3)}
66% {background-position: 0 calc(100%/3),calc(100%/3) 0 }
80%,
100% {background-position: 0 calc(100%/3),0 0 }
}

